import { Overlay, OverlayRef } from '@angular/cdk/overlay';
import { ComponentPortal } from '@angular/cdk/portal';
import { Injectable } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { InitLoadingComponent } from '../components/init-loading/init-loading.component';
import { LoadingComponent } from '../components/loading/loading.component';

@Injectable()
export class NotificationService {
  private loadingOverlayRef: OverlayRef;

  constructor(
    private snackBar: MatSnackBar,
    private dialog: MatDialog,
    private overlay: Overlay
  ) {
  }

  showWarning(message: string): void {
    this.snackBar.open(message || 'Something went wrong', 'Dismiss', {
      duration: 5000,
      horizontalPosition: 'center',
      verticalPosition: 'top'
    });
  }

  showError(message: string): void {
    this.snackBar.open(message, 'Dismiss', {
      duration: 5000,
      horizontalPosition: 'center',
      verticalPosition: 'top'
    });
  }

  showMessage(message: string, delay = 5000): void {
    this.snackBar.open(message, undefined, {
      duration: delay,
      horizontalPosition: 'right',
      verticalPosition: 'bottom'
    });
  }

  showInitLoading(element: HTMLElement = document.body): void {
    const portal = new ComponentPortal(InitLoadingComponent);
    const positionStrategy = this.overlay.position().flexibleConnectedTo(element);
    const width = element.offsetWidth;
    const height = element.offsetHeight;

    positionStrategy.withPositions([{
      offsetX: 0,
      offsetY: 0,
      originX: 'center',
      originY: 'center',
      overlayX: 'center',
      overlayY: 'center'
    }]);

    if (!this.loadingOverlayRef) {
      this.initLoadingOverlayRef();
    }
    if (element === document.body) {
      this.loadingOverlayRef.updateSize({
        width: '100%',
        height: '100%'
      });
    } else {
      this.loadingOverlayRef.updateSize({
        width,
        height
      });
    }
    this.loadingOverlayRef.updatePositionStrategy(positionStrategy);

    if(this.loadingOverlayRef.hasAttached()) {
      this.loadingOverlayRef.detach();
    }
    this.loadingOverlayRef.attach(portal);
  }

  showLoading(element: HTMLElement = document.body): void {
    const portal = new ComponentPortal(LoadingComponent);
    const positionStrategy = this.overlay.position().flexibleConnectedTo(element);
    const width = element.offsetWidth;
    const height = element.offsetHeight;

    positionStrategy.withPositions([{
      offsetX: 0,
      offsetY: 0,
      originX: 'center',
      originY: 'center',
      overlayX: 'center',
      overlayY: 'center'
    }]);

    if (!this.loadingOverlayRef) {
      this.initLoadingOverlayRef();
    }
    if (element === document.body) {
      this.loadingOverlayRef.updateSize({
        width: '100%',
        height: '100%'
      });
    } else {
      this.loadingOverlayRef.updateSize({
        width,
        height
      });
    }
    this.loadingOverlayRef.updatePositionStrategy(positionStrategy);

    if(this.loadingOverlayRef.hasAttached()) {
      this.loadingOverlayRef.detach();
    }
    this.loadingOverlayRef.attach(portal);
  }

  hideLoading(): void {
    if(this.loadingOverlayRef && this.loadingOverlayRef.hasAttached()) {
      this.loadingOverlayRef.detach();
    }
  }

  private initLoadingOverlayRef(): OverlayRef {
    return this.loadingOverlayRef = this.overlay.create({
      backdropClass: 'cdk-overlay-invisible-backdrop',
      disposeOnNavigation: false,
      hasBackdrop: true,
      scrollStrategy: this.overlay.scrollStrategies.noop()
    });
  }
}
