import { AfterViewInit, Component, Input, OnDestroy } from '@angular/core';
import { Subscription } from 'rxjs';
import { debounceTime } from 'rxjs/operators';
import * as d3 from 'd3';

import { IChartOptionsBase } from './chart-options';
import { ISunburstData, IChartValue } from './chart-data';
import { EventService } from '../services/event.service';

type ChartSerieData = Array<Array<IChartValue> | ISunburstData>;

@Component({
  template: '',
})
export abstract class ChartBase implements AfterViewInit, OnDestroy {
  @Input() set options(value: IChartOptionsBase) {
    this._options = { ...this._options, ...value };
    this.clear();
    this.draw();
  }
  get options(): IChartOptionsBase {
    return this._options;
  }

  @Input() set data(value: ChartSerieData) {
    this._data = value;
    this.clear();
    this.draw();
  }
  get data(): ChartSerieData {
    return this._data;
  }

  protected _options: IChartOptionsBase;
  protected _data: ChartSerieData;
  protected color: (value: string | number) => string = d3.scaleSequential(d3.interpolateBlues);
  protected subscription: Subscription;

  constructor(protected eventService: EventService) {}

  ngAfterViewInit(): void {
    this.listenViewportResize();
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  abstract draw(): void;
  abstract clear(): void;

  protected coerceNumber(
    value: number | string,
    dependedValue: number,
  ): number {
    if (typeof value === 'undefined') {
      return dependedValue;
    }
    if (typeof value === 'string') {
      if (value.endsWith('%')) {
        return (dependedValue * parseInt(value)) / 100;
      } else {
        return parseInt(value);
      }
    }

    return value as number;
  }

  protected getColor(index: number): string {
    if (this.options.seriesColor) {
      return this.options.seriesColor[index];
    } else {
      this.color(index);
    }

    return '#000'
  }

  protected getDisplayValue(value: IChartValue): string {
    if (typeof this.options.valueFormat === 'function') {
      return this.options.valueFormat(value);
    }
    return value ? value.toString() : '';
  }

  protected listenViewportResize() {
    this.subscription.add(
      this.eventService.onViewportDimensionChange().pipe(
        debounceTime(300)
      ).subscribe((event) => {
        this.clear();
        this.draw();
      })
    );
  }
}
