import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';

import { CanDeactivateGuard } from 'app/authorization/can-deactivate-guard.service';
import { SelectivePreloadingStrategy } from 'app/authorization/selective-preloading-strategy';
import { AuthGuard } from 'app/authorization/auth-guard.service';
import { LoginGuard } from 'app/authorization/login.guard';

const appRoutes: Routes = [
  {
    path: 'admin',
    canLoad: [AuthGuard],
    loadChildren: () =>
      import('./admin/admin.module').then((m) => m.AdminModule),
  },
  {
    path: 'sign-in',
    canLoad: [LoginGuard],
    loadChildren: () =>
      import('./login/login.module').then((m) => m.LoginModule),
  },
  {
    path: 'reform/web/login',
    loadChildren: () =>
      import('./login/login.module').then((m) => m.LoginModule),
  },
  {
    path: '',
    redirectTo: '/admin',
    pathMatch: 'full',
  },
  {
    path: '**',
    redirectTo: '/admin',
  },
];

@NgModule({
  imports: [
    RouterModule.forRoot(appRoutes, {
      enableTracing: false,
      preloadingStrategy: SelectivePreloadingStrategy,
      relativeLinkResolution: 'legacy',
    }),
  ],
  exports: [RouterModule],
  providers: [CanDeactivateGuard, SelectivePreloadingStrategy],
})
export class AppRoutingModule {}
