import { Injectable } from '@angular/core';



@Injectable()
export class AlgorithmService {

  constructor() { }

  deviceOfDuff(values: Array<any>, process: (value?: any, index?: number) => void): void {
    const length = values.length;
    let iterations = Math.floor(length / 8);
    let leftover = length % 8;
    let i = 0;

    if (leftover > 0) {
      do {
        process(values[i++], i);
      } while (--leftover > 0);
    }

    do {
      process(values[i++], i);
      process(values[i++], i);
      process(values[i++], i);
      process(values[i++], i);
      process(values[i++], i);
      process(values[i++], i);
      process(values[i++], i);
      process(values[i++], i);
    } while (--iterations > 0);
  }

  reverseDeviceOfDuff(values: Array<any>, process: (value?: any, index?: number) => void): void {
    const length = values.length;
    let iterations = Math.floor(length / 8);
    let leftover = length % 8;
    let i = length - 1;

    if (leftover > 0) {
      do {
        process(values[i--], i);
      } while (--leftover > 0);
    }

    do {
      process(values[i--], i);
      process(values[i--], i);
      process(values[i--], i);
      process(values[i--], i);
      process(values[i--], i);
      process(values[i--], i);
      process(values[i--], i);
      process(values[i--], i);
    } while (--iterations > 0);
  }
}
