import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';

import { IBaseResponse } from '../interface/http-response-types';



@Injectable()
export class RequestService {
  public readonly TIME_ZONE_ID: string = 'Asia/Shanghai';
  private readonly REQUST_HEADERS = new HttpHeaders({
    'Accept': 'application/json, text/plain, */*',
    'Content-Type': 'application/json',
    'X-Appver': '',
    'X-Deviceid': '0',
    'X-Mc': '0',
    'X-Platform': '0'
  });
  private readonly domain: string = 'https://www.wacai.com';

  constructor(
    private http: HttpClient
  ) { }

  get(url: string, params?: any): Observable<IBaseResponse> {
    return this.http.get(
      this.domain + '/' + url + '?___t=' + Date.now(),
      {
      headers: this.REQUST_HEADERS,
      responseType: 'json',
      params,
      withCredentials: true
    }) as Observable<IBaseResponse>;
  }

  post(url: string, params: any): Observable<IBaseResponse> {
    return this.http.post(
      this.domain + '/' + url + '?___t=' + Date.now(),
      JSON.stringify(params),
      {
      headers: this.REQUST_HEADERS,
      responseType: 'json',
      withCredentials: true
    }) as Observable<IBaseResponse>;
  }
}
