import { Injectable } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { Observable, Subject } from 'rxjs';



@Injectable()
export class CommunicationService {
  private deleteCommand = new Subject<void>();
  private refreshCommand = new Subject<void>();
  private fullScreenCommand = new Subject<boolean>();
  private fullScreenExpanded = false;

  constructor() { }

  acceptRefreshCommand(): Observable<void> {
    return this.refreshCommand.asObservable();
  }

  giveRefreshCommand(): void {
    this.refreshCommand.next();
  }

  acceptFullScreenCommand(): Observable<boolean> {
    return this.fullScreenCommand.asObservable();
  }

  giveFullScreenCommand(): void {
    this.fullScreenExpanded = !this.fullScreenExpanded;
    this.fullScreenCommand.next(this.fullScreenExpanded);
  }

  findRoute(routes: Array<ActivatedRoute>, component): ActivatedRoute {
    let findRoute: ActivatedRoute;
  
    routes.some((route) => {
      if (route.component === component) {
        findRoute = route;
        return true;
      }
      findRoute = this.findRoute(route.children, component);
      if (findRoute) {
        return true;
      }
      return false;
    });

    return findRoute;
  }
}
