import { Inject, Injectable } from '@angular/core';
import { CanLoad, UrlTree, Route, Router } from '@angular/router';
import { Observable, of } from 'rxjs';
import { map } from 'rxjs/operators';

import { AuthGuard } from './auth-guard.service';
import { AUTH_SERVICE_TOKEN, IAuthService } from './auth.service';



@Injectable({
  providedIn: 'root'
})
export class LoginGuard implements CanLoad {
  constructor(
    private router: Router,
    private authGuard: AuthGuard,
    @Inject(AUTH_SERVICE_TOKEN) private authService: IAuthService
  ) {
  }

  canLoad(route: Route): Observable<boolean | UrlTree> | boolean | UrlTree {
    if (this.authGuard.isTimeount()) {
      return of(true);
    }
    return this.authGuard.checkLogin(route.path).pipe(
      map((data) => {
        if (data) {
          this.router.navigate(['/']);
        }
        return !data;
      })
    );
  }

}
