import { Inject, Injectable } from '@angular/core';
import { CanActivate, Router, ActivatedRouteSnapshot, RouterStateSnapshot, CanActivateChild, CanLoad, Route, UrlTree } from '@angular/router';
import { Observable, of } from 'rxjs';
import { finalize, map } from 'rxjs/operators';

import { NotificationService } from 'app/shared/services/notification.service';
import { IAuthService, AUTH_SERVICE_TOKEN } from './auth.service';



@Injectable()
export class AuthGuard implements CanActivate, CanActivateChild, CanLoad {
  private timeoutCount: number = 0;

  constructor(
    private router: Router,
    private notification: NotificationService,
    @Inject(AUTH_SERVICE_TOKEN) private authService: IAuthService
  ) { }

  canActivate(route: ActivatedRouteSnapshot, state: RouterStateSnapshot):
    Observable<boolean | UrlTree> | boolean | UrlTree {
    const url: string = state.url;

    return this.checkLogin(url);
  }

  canActivateChild(route: ActivatedRouteSnapshot, state: RouterStateSnapshot):
    Observable<boolean | UrlTree> | boolean | UrlTree {
    return this.canActivate(route, state);
  }

  canLoad(route: Route): Observable<boolean | UrlTree> | boolean | UrlTree {
    const url = `/${route.path}`;

    return this.checkLogin(url);
  }

  checkLogin(url: string): Observable<boolean> {
    // Store the attempted URL for redirecting
    // this.authService.redirectUrl = url;

    if (this.isTimeount()) {
      return of(false);
    }
    if (this.authService.isLoggedIn) {
      return of(true);
    }
    this.notification.showInitLoading();
    return this.authService.checkSignInStatus().pipe(
      finalize(() => {
        this.timeoutCount++;
        this.notification.hideLoading();
      }),
      map((value: boolean) => {
        this.authService.isLoggedIn = value;
        if (value) {
          this.router.navigateByUrl(this.authService.redirectUrl);
        } else {
          this.router.navigate(['/sign-in']);
        }
        return value;
      })
    );
  }

  isTimeount(): boolean {
    return this.timeoutCount > 4;
  }
}
