import { Component, Input, OnDestroy, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';

import { MENU_ITEMS } from 'src/data/menu-items';
import { WACAI_MENU } from 'src/data/wacai-menu';
import { INavigationMenuItem } from 'app/admin/navigation-menu/i-navigation-menu';



@Component({
  selector: 'app-breadcrumb',
  templateUrl: './breadcrumb.component.html',
  styleUrls: ['./breadcrumb.component.scss']
})
export class BreadcrumbComponent implements OnInit, OnDestroy {
  @Input('adminBreadcrumb') data: Array<INavigationMenuItem> = [];

  private oldTitle: string;

  constructor(
    private router: Router,
    private route: ActivatedRoute
  ) { }

  ngOnInit(): void {
    const menuPaths = this.data;
    const routePaths= this.route.routeConfig.path.split('/').reverse();
    let url = '';

    this.route.pathFromRoot.forEach((item) => {
      if (item.snapshot.url.length) {
        url += '/' + item.snapshot.url.join('/');
      }
    });
    url = url.split('/').reverse().filter((path, index) => {
      return !routePaths[index] || !routePaths[index].startsWith(':');
    }).reverse().join('/');

    menuPaths.length = 0;
    this.findRoute(MENU_ITEMS.concat(WACAI_MENU), url);
    this.oldTitle = document.title;
    document.title = menuPaths[menuPaths.length - 1]?.title;
  }

  ngOnDestroy(): void {
    document.title = this.oldTitle;
  }

  private findRoute(items: INavigationMenuItem[], url: string): boolean {
    let flag = false;
    let entry: INavigationMenuItem;

    flag = items.some((item) => {
      entry = item;
      return url.endsWith(item.url) 
        || (item.children && this.findRoute(item.children, url));
    });
    if (flag && entry) {
      this.data.unshift(entry);
    }
    return flag;
  }
}
