import { Injectable } from '@angular/core';
import * as md5 from 'md5';



@Injectable()
export class CodeGeneratorService {
  private readonly chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';

  constructor() { }

  generateBIZID(): string {
    const chars = this.chars.split('');
    const result = [];
    let length = 16;
    let i = 0;
  
    for (length = length || chars.length, i = 0; i < 32; i++) {
      result[i] = chars[0 | Math.random() * length];
    }
    return result.join('')
  }

  compilePassword(password: string): string {
    return md5(password);
  }
}
