import { HttpClient, HttpParams, HttpResponse } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable, of } from 'rxjs';
import { catchError, map } from 'rxjs/operators';

import { IAuthService } from 'app/authorization/auth.service';
import { ILoginResponse, IBookResponse } from '../interface/http-response-types';
import { NotificationService } from 'app/shared/services/notification.service';
import { CodeGeneratorService } from './code-generator.service';
import { RequestService } from './request.service';



@Injectable({
  providedIn:'root'
})
export class WacaiAuthService implements IAuthService {
  isLoggedIn: boolean = false;
  redirectUrl: string = localStorage.getItem('redirectUrl') || '/admin';

  private token: string;

  constructor(
    private http: HttpClient,
    private notification: NotificationService,
    private generatorService: CodeGeneratorService,
    private requestService: RequestService
  ) {
  }

  login(account: string, password: string): Observable<boolean> {
    const body = new HttpParams({
      fromObject: {
        username: account,
        password: this.generatorService.compilePassword(password),
        autoLogin: 'false',
        imgType: 'KAPTCHA',
        url: 'https://www.wacai.com/'
      }
    });

    return this.http.post('https://user.wacai.com/reform/web/pwd_login', body.toString(), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
      },
      observe: 'response',
      withCredentials: true
    }).pipe(
      map((response: HttpResponse<ILoginResponse>) => {
        const data = response.body;

        if (!!data.data[0] && data.data[0].token) {
          const now = new Date();

          this.isLoggedIn = true;
          now.setTime(now.getTime() + (24 * 60 * 60 * 1000));
          this.setToken(data.data[0].token);
          document.cookie = 'access_token=' + this.getToken() + '; expires=' + now.toUTCString() + '; path=/; httpOnly=false; Secure=false; SameSite=None';
        } else {
          this.isLoggedIn = false;
          this.notification.showWarning(data.error);
        }
        return this.isLoggedIn;
      })
    ) as Observable<boolean>;
  }

  logout(): Observable<boolean> {
    return this.http.get('https://user.wacai.com/member/loginOut').pipe(
      map((data: ILoginResponse) => {
        if (!!data.data[0] && !data.error) {
          this.isLoggedIn = false;
        } else {
          this.notification.showWarning(data.error);
        }
        return !this.isLoggedIn;
      })
    ) as Observable<boolean>;
  }

  checkSignInStatus(): Observable<boolean> {
    return this.requestService.get('activity/bkk-frontier/api/v2/book/web/query').pipe(
      catchError(() => {
        return of(false);
      }),
      map((data: IBookResponse) => {
        return !!data && !!data.data && !data.error;
      })
    );
  }

  getToken(): string {
    return this.token;
  }

  protected setToken(value: string): void {
    this.token = value;
  }
}