import { Component, ElementRef, OnInit, Renderer2 } from '@angular/core';

@Component({
  selector: 'app-router-outlet-window',
  template: '<router-outlet></router-outlet>'
})
export class RouterOutletWindowComponent implements OnInit {

  constructor(
    private elementRef: ElementRef,
    private renderer: Renderer2
  ) { }

  ngOnInit(): void {
    const element = this.elementRef.nativeElement;

    this.renderer.addClass(element, 'd-flex');
    this.renderer.addClass(element, 'w-100');
    this.renderer.addClass(element, 'h-100');
    // this.renderer.addClass(element, 'overflow-hidden');
  }

}
