import {
  AfterViewInit,
  Component,
  ElementRef,
  OnInit,
  Renderer2,
} from '@angular/core';
import { Subscription } from 'rxjs';
import * as d3 from 'd3';

import { BarChartOptions } from '../chart-options';
import { ChartBase } from '../chart-base';
import { EventService } from 'app/shared/services/event.service';
import { AlgorithmService } from 'app/shared/services/algorithm.service';

type LAYOUT_TYPE = 'grouped' | 'stacked';

@Component({
  selector: 'app-bar-chart',
  template: '',
  styleUrls: ['./bar-chart.component.scss'],
})
export class BarChartComponent
  extends ChartBase
  implements OnInit, AfterViewInit {
  private svg: d3.Selection<SVGSVGElement, undefined, null, undefined>;
  private bars: d3.Selection<
    d3.BaseType,
    unknown,
    Element | d3.EnterElement | Document | Window | SVGGElement,
    any
  >;
  private x: d3.ScaleBand<number | string>;
  private y: d3.ScaleLinear<number, number, never>;

  private yGroupedMax: number;
  private yStackedMax: number;

  protected _options = new BarChartOptions();
  protected subscription = new Subscription();

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private renderer: Renderer2,
    protected eventService: EventService,
    private algorithm: AlgorithmService
  ) {
    super(eventService);
  }

  ngOnInit(): void {}

  ngAfterViewInit(): void {
    super.ngAfterViewInit();

    setTimeout(() => {
      this.draw();
    });
  }

  updateLayout(layout: LAYOUT_TYPE) {
    if (layout === 'stacked') {
      this.transitionStacked();
    } else {
      this.transitionGrouped();
    }
  }

  transitionGrouped(): void {
    const delayValue = this.options.delay;
    const numOfSeries = this.getNumOfSeries();

    this.y.domain([0, this.yGroupedMax]);

    this.bars
      .transition()
      .duration(500)
      .delay((d, i) => i * delayValue)
      .attr(
        'x',
        (d, i) => this.x(i) + (this.x.bandwidth() / numOfSeries) * d[2],
      )
      .attr('width', this.x.bandwidth() / numOfSeries)
      .transition()
      .attr('y', (d) => this.y(d[1] - d[0]))
      .attr('height', (d) => this.y(0) - this.y(d[1] - d[0]));
  }

  transitionStacked(): void {
    const delayValue = this.options.delay;

    this.y.domain([0, this.yStackedMax]);

    this.bars
      .transition()
      .duration(500)
      .delay((d, i) => i * delayValue)
      .attr('y', (d) => this.y(d[1]))
      .attr('height', (d) => this.y(d[0]) - this.y(d[1]))
      .transition()
      .attr('x', (d, i) => this.x(i))
      .attr('width', this.x.bandwidth());
  }

  draw(): void {
    const data = this.data as Array<Array<number | Date>>;

    if (!data) {
      return;
    }
    const parentEl = this.elementRef.nativeElement.parentElement;
    const width = this.coerceNumber(this.options.width, parentEl.offsetWidth);
    const height = this.coerceNumber(
      this.options.height,
      parentEl.offsetHeight,
    );
    const margin = { top: 0, right: 0, bottom: 10, left: 0 };

    const dataLength = data.length;
    const seriesDatas = [];
    // number of series
    const n = this.getNumOfSeries();
    const xz = d3.range(dataLength);
    // const xz = data.map(item => (item[0] as Date).getTime());

    this.algorithm.deviceOfDuff(data, (item: Array<number>, index) => {
      item && item.slice(1).forEach((value, i) => {
        if (!Array.isArray(seriesDatas[i])) {
          seriesDatas[i] = [];
        }
        seriesDatas[i].push(value);
      });
    });

    const y01z = d3
      .stack()
      .keys(d3.range(n))(d3.transpose(seriesDatas)) // stacked seriesDatas
      .map((data, i) => data.map(([y0, y1]) => [y0, y1, i]));

    this.yGroupedMax = d3.max(seriesDatas, (y) => d3.max(y));
    this.yStackedMax = d3.max(y01z, (y) => d3.max(y, (d) => d[1]));

    this.x = d3
      .scaleBand()
      .domain(xz)
      .rangeRound([margin.left, width - margin.right])
      .padding(0.08);

    this.y = d3
      .scaleLinear()
      .domain([0, this.yStackedMax])
      .range([height - margin.bottom, margin.top]);

    this.color = d3
      .scaleSequential(d3.interpolateBlues)
      .domain([-0.5 * n, 1.5 * n]);

    const xAxis = (svg) =>
      svg
        .append('g')
        .attr('transform', `translate(0,${height - margin.bottom})`)
        .call(
          d3
            .axisBottom(this.x)
            .tickSizeOuter(0)
            .tickFormat(() => ''),
        );

    const svg = d3.create('svg').attr('viewBox', [0, 0, width, height]);

    this.svg = svg;
    this.bars = svg
      .selectAll('g')
      .data(y01z)
      .join('g')
      .attr('fill', (d, i) => this.getColor(i))
      .selectAll('rect')
      .data((d) => d)
      .join('rect')
      .attr('x', (d, i) => this.x(i))
      .attr('y', height - margin.bottom)
      .attr('width', this.x.bandwidth())
      .attr('height', 0);

    svg.append('g').call(xAxis);

    this.renderer.appendChild(this.elementRef.nativeElement, svg.node());
    this.updateLayout('stacked');
  }

  clear(): void {
    if (this.svg) {
      this.renderer.removeChild(this.elementRef.nativeElement, this.svg.node());
      this.svg = undefined;
    }
  }

  private getNumOfSeries(): number {
    return this.data && this.data[0] ? (this.data[0] as Array<number>).length - 1 : 0;
  }
}
